import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import {
    getTodayAttendance,
    markAttendance,
    markBulkAttendance,
    getAttendances,
    updateAttendance,
    deleteAttendance,
    getAttendanceSummary,
    getAttendanceCompanies
} from '../services/attendanceService';
import './AttendanceManagement.css';

function AttendanceManagement() {
    const { user } = useAuth();
    const [todayData, setTodayData] = useState(null);
    const [attendanceHistory, setAttendanceHistory] = useState([]);
    const [summary, setSummary] = useState(null);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [error, setError] = useState(null);
    const [success, setSuccess] = useState(null);
    const [activeTab, setActiveTab] = useState('today');
    const [selectedWorkers, setSelectedWorkers] = useState({});
    const [startDate, setStartDate] = useState(getFirstDayOfMonth());
    const [endDate, setEndDate] = useState(getTodayDate());
    const [workerSearch, setWorkerSearch] = useState('');
    const [companies, setCompanies] = useState([]);
    const [selectedCompany, setSelectedCompany] = useState('');
    const [filters, setFilters] = useState({
        date: '',
        worker_id: '',
        status: ''
    });

    useEffect(() => {
        if (user?.role === 'super_admin') {
            fetchCompanies();
        }
        fetchTodayAttendance();
        fetchAttendanceHistory();
        fetchSummary();
    }, []);

    useEffect(() => {
        if (activeTab === 'history') {
            fetchAttendanceHistory();
        }
    }, [filters]);

    useEffect(() => {
        fetchSummary();
    }, [startDate, endDate]);

    useEffect(() => {
        if (selectedCompany || user?.role === 'supervisor') {
            fetchTodayAttendance();
            fetchAttendanceHistory();
            fetchSummary();
        }
    }, [selectedCompany]);

    function getFirstDayOfMonth() {
        const date = new Date();
        return new Date(date.getFullYear(), date.getMonth(), 1).toISOString().split('T')[0];
    }

    function getTodayDate() {
        return new Date().toISOString().split('T')[0];
    }

    const fetchCompanies = async () => {
        try {
            const data = await getAttendanceCompanies();
            setCompanies(data);
        } catch (error) {
            console.error('Error fetching companies:', error);
        }
    };

    const fetchTodayAttendance = async () => {
        try {
            setLoading(true);
            setError(null);
            const companyId = user?.role === 'super_admin' ? selectedCompany : null;
            const data = await getTodayAttendance(companyId);
            setTodayData(data);
            // Initialize selected workers with default 'present' status
            const initial = {};
            data.unmarked_workers?.forEach(worker => {
                initial[worker.id] = 'present';
            });
            setSelectedWorkers(initial);
        } catch (error) {
            console.error('Error fetching today attendance:', error);
            const errorMessage = error.response?.data?.message || error.message || 'Failed to load today\'s attendance data';
            setError(errorMessage);
            setTimeout(() => setError(null), 5000);
        } finally {
            setLoading(false);
        }
    };

    const fetchAttendanceHistory = async () => {
        try {
            setLoading(true);
            const params = {};
            if (filters.date) params.date = filters.date;
            if (filters.worker_id) params.worker_id = filters.worker_id;
            if (filters.status) params.status = filters.status;

            const data = await getAttendances(params);
            setAttendanceHistory(data.data || []);
        } catch (error) {
            console.error('Error fetching attendance history:', error);
        } finally {
            setLoading(false);
        }
    };

    const fetchSummary = async () => {
        try {
            const params = {
                start_date: startDate,
                end_date: endDate
            };
            const data = await getAttendanceSummary(params);
            setSummary(data);
        } catch (error) {
            console.error('Error fetching summary:', error);
            setError('Failed to load attendance summary');
            setTimeout(() => setError(null), 5000);
        }
    };

    const handleMarkAttendance = async (workerId, status) => {
        try {
            setSubmitting(true);
            setError(null);
            const data = {
                worker_id: workerId,
                date: getTodayDate(),
                status: status,
                check_in_time: status === 'present' || status === 'half_day' ? '09:00' : null,
            };
            await markAttendance(data);
            await fetchTodayAttendance();
            await fetchSummary();
            setSuccess('Attendance marked successfully!');
            setTimeout(() => setSuccess(null), 3000);
        } catch (error) {
            const message = error.response?.data?.message || 'Error marking attendance';
            setError(message);
            setTimeout(() => setError(null), 5000);
        } finally {
            setSubmitting(false);
        }
    };

    const handleBulkMark = async () => {
        if (Object.keys(selectedWorkers).length === 0) {
            setError('Please select at least one worker');
            setTimeout(() => setError(null), 3000);
            return;
        }

        const attendances = Object.entries(selectedWorkers).map(([workerId, status]) => ({
            worker_id: parseInt(workerId),
            status: status,
            check_in_time: status === 'present' || status === 'half_day' ? '09:00' : null,
        }));

        try {
            setSubmitting(true);
            setError(null);
            const data = {
                date: getTodayDate(),
                attendances: attendances
            };
            await markBulkAttendance(data);
            await fetchTodayAttendance();
            await fetchSummary();
            setSelectedWorkers({});
            setSuccess(`Bulk attendance marked successfully for ${attendances.length} workers!`);
            setTimeout(() => setSuccess(null), 3000);
        } catch (error) {
            const message = error.response?.data?.message || 'Error marking bulk attendance';
            setError(message);
            setTimeout(() => setError(null), 5000);
        } finally {
            setSubmitting(false);
        }
    };

    const handleUpdateAttendance = async (id, newStatus) => {
        try {
            setSubmitting(true);
            setError(null);
            await updateAttendance(id, { status: newStatus });
            await fetchAttendanceHistory();
            await fetchTodayAttendance();
            setSuccess('Attendance updated successfully!');
            setTimeout(() => setSuccess(null), 3000);
        } catch (error) {
            const message = error.response?.data?.message || 'Error updating attendance';
            setError(message);
            setTimeout(() => setError(null), 5000);
        } finally {
            setSubmitting(false);
        }
    };

    const handleDeleteAttendance = async (id) => {
        if (window.confirm('Are you sure you want to delete this attendance record?')) {
            try {
                setSubmitting(true);
                setError(null);
                await deleteAttendance(id);
                await fetchAttendanceHistory();
                await fetchTodayAttendance();
                await fetchSummary();
                setSuccess('Attendance deleted successfully!');
                setTimeout(() => setSuccess(null), 3000);
            } catch (error) {
                const message = error.response?.data?.message || 'Error deleting attendance';
                setError(message);
                setTimeout(() => setError(null), 5000);
            } finally {
                setSubmitting(false);
            }
        }
    };

    const handleWorkerSelect = (workerId, status) => {
        setSelectedWorkers(prev => ({
            ...prev,
            [workerId]: status
        }));
    };

    const handleSelectAll = (status) => {
        const newSelection = {};
        todayData?.unmarked_workers?.forEach(worker => {
            newSelection[worker.id] = status;
        });
        setSelectedWorkers(newSelection);
    };

    const getStatusBadgeClass = (status) => {
        const classes = {
            present: 'status-badge status-present',
            absent: 'status-badge status-absent',
            half_day: 'status-badge status-half-day',
            leave: 'status-badge status-leave'
        };
        return classes[status] || 'status-badge';
    };

    const formatDate = (dateString) => {
        return new Date(dateString).toLocaleDateString('en-US', {
            year: 'numeric',
            month: 'short',
            day: 'numeric'
        });
    };

    const formatTime = (timeString) => {
        if (!timeString) return '-';
        return new Date(`2000-01-01 ${timeString}`).toLocaleTimeString('en-US', {
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    const filterWorkersBySearch = (workers) => {
        if (!workerSearch) return workers;
        const search = workerSearch.toLowerCase();
        return workers.filter(worker => {
            // For unmarked workers (direct worker objects)
            if (worker.name) {
                return worker.name.toLowerCase().includes(search) ||
                       worker.position?.toLowerCase().includes(search) ||
                       worker.contact_number?.includes(search) ||
                       worker.team?.toLowerCase().includes(search);
            }
            // For marked attendances (attendance objects with nested worker)
            if (worker.worker) {
                return worker.worker.name.toLowerCase().includes(search) ||
                       worker.worker.position?.toLowerCase().includes(search) ||
                       worker.worker.contact_number?.includes(search) ||
                       worker.worker.team?.toLowerCase().includes(search);
            }
            return false;
        });
    };

    return (
        <div className="attendance-management">
            {/* Notifications */}
            {error && (
                <div className="notification error">
                    <span className="notification-icon">⚠️</span>
                    <span className="notification-message">{error}</span>
                    <button className="notification-close" onClick={() => setError(null)}>×</button>
                </div>
            )}
            {success && (
                <div className="notification success">
                    <span className="notification-icon">✅</span>
                    <span className="notification-message">{success}</span>
                    <button className="notification-close" onClick={() => setSuccess(null)}>×</button>
                </div>
            )}

            <div className="attendance-header">
                <h2>Attendance Management</h2>
                {user?.role === 'super_admin' && (
                    <div className="company-selector">
                        <select 
                            value={selectedCompany} 
                            onChange={(e) => setSelectedCompany(e.target.value)}
                            className="company-select"
                        >
                            <option value="">Select Company</option>
                            {companies.map(company => (
                                <option key={company.id} value={company.id}>
                                    {company.name}
                                </option>
                            ))}
                        </select>
                    </div>
                )}
                <div className="tab-buttons">
                    <button 
                        className={activeTab === 'today' ? 'active' : ''}
                        onClick={() => setActiveTab('today')}
                    >
                        Today's Attendance
                    </button>
                    <button 
                        className={activeTab === 'history' ? 'active' : ''}
                        onClick={() => setActiveTab('history')}
                    >
                        History
                    </button>
                    <button 
                        className={activeTab === 'summary' ? 'active' : ''}
                        onClick={() => setActiveTab('summary')}
                    >
                        Summary
                    </button>
                </div>
            </div>

            {/* Today's Attendance Tab */}
            {activeTab === 'today' && (
                <div className="today-tab">
                    {user?.role === 'super_admin' && !selectedCompany ? (
                        <div className="company-selection-required">
                            <div className="selection-icon">🏢</div>
                            <h3>Company Selection Required</h3>
                            <p>Please select a company from the dropdown above to view attendance data.</p>
                        </div>
                    ) : loading ? (
                        <div className="loading-container">
                            <div className="loading-spinner"></div>
                            <p>Loading today's attendance...</p>
                        </div>
                    ) : todayData ? (
                        <>
                            <div className="stats-cards">
                                <div className="stat-card total-workers">
                                    <div className="stat-icon">👥</div>
                                    <div className="stat-content">
                                        <h3>Total Workers</h3>
                                        <p className="stat-value">{todayData.total_workers}</p>
                                    </div>
                                </div>
                                <div className="stat-card marked-workers">
                                    <div className="stat-icon">✅</div>
                                    <div className="stat-content">
                                        <h3>Marked</h3>
                                        <p className="stat-value">{todayData.marked_count}</p>
                                        <p className="stat-percent">
                                            {todayData.total_workers > 0 ? Math.round((todayData.marked_count / todayData.total_workers) * 100) : 0}%
                                        </p>
                                    </div>
                                </div>
                                <div className="stat-card unmarked-workers">
                                    <div className="stat-icon">⏳</div>
                                    <div className="stat-content">
                                        <h3>Unmarked</h3>
                                        <p className="stat-value">{todayData.unmarked_count}</p>
                                        <p className="stat-percent">
                                            {todayData.total_workers > 0 ? Math.round((todayData.unmarked_count / todayData.total_workers) * 100) : 0}%
                                        </p>
                                    </div>
                                </div>
                            </div>

                            <div className="unmarked-section">
                                {todayData.unmarked_count > 0 && (
                                    <>
                                        <div className="section-header">
                                            <h3>Mark Attendance for {formatDate(todayData.date)}</h3>
                                            <div className="bulk-actions">
                                                <button 
                                                    className="btn btn-sm btn-success"
                                                    onClick={() => handleSelectAll('present')}
                                                    disabled={submitting}
                                                >
                                                    📋 Mark All Present
                                                </button>
                                                <button 
                                                    className="btn btn-sm btn-danger"
                                                    onClick={() => handleSelectAll('absent')}
                                                    disabled={submitting}
                                                >
                                                    ❌ Mark All Absent
                                                </button>
                                                <button 
                                                    className="btn btn-sm btn-primary"
                                                    onClick={handleBulkMark}
                                                    disabled={Object.keys(selectedWorkers).length === 0 || submitting}
                                                >
                                                    {submitting ? '⏳ Submitting...' : '✅ Submit Attendance'}
                                                </button>
                                            </div>
                                        </div>
                                    </>
                                )}

                                <div className="search-box">
                                    <input
                                        type="text"
                                        placeholder="🔍 Search workers by name, position, contact, or team..."
                                        value={workerSearch}
                                        onChange={(e) => setWorkerSearch(e.target.value)}
                                        className="worker-search-input"
                                    />
                                    {workerSearch && (
                                        <button 
                                            className="clear-search-btn"
                                            onClick={() => setWorkerSearch('')}
                                        >
                                            ✕
                                        </button>
                                    )}
                                </div>

                                {todayData.unmarked_count > 0 && (
                                    <div className="workers-grid">
                                        {filterWorkersBySearch(todayData.unmarked_workers || []).map(worker => (
                                            <div key={worker.id} className="worker-card">
                                                <div className="worker-info">
                                                    <h4>{worker.name}</h4>
                                                    <p>{worker.position}</p>
                                                    <span className="team-badge">{worker.team}</span>
                                                </div>
                                                <div className="status-buttons">
                                                    <button
                                                        className={`status-btn present ${selectedWorkers[worker.id] === 'present' ? 'selected' : ''}`}
                                                        onClick={() => handleWorkerSelect(worker.id, 'present')}
                                                    >
                                                        Present
                                                    </button>
                                                    <button
                                                        className={`status-btn absent ${selectedWorkers[worker.id] === 'absent' ? 'selected' : ''}`}
                                                        onClick={() => handleWorkerSelect(worker.id, 'absent')}
                                                    >
                                                        Absent
                                                    </button>
                                                    <button
                                                        className={`status-btn half-day ${selectedWorkers[worker.id] === 'half_day' ? 'selected' : ''}`}
                                                        onClick={() => handleWorkerSelect(worker.id, 'half_day')}
                                                    >
                                                        Half Day
                                                    </button>
                                                    <button
                                                        className={`status-btn leave ${selectedWorkers[worker.id] === 'leave' ? 'selected' : ''}`}
                                                        onClick={() => handleWorkerSelect(worker.id, 'leave')}
                                                    >
                                                        Leave
                                                    </button>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                )}

                                {todayData.unmarked_count === 0 && (
                                    <div className="no-results">
                                        <p>🎉 All workers have been marked for today!</p>
                                        <small>Great job keeping attendance up to date!</small>
                                    </div>
                                )}
                            </div>

                            {todayData.marked_count > 0 && (
                                <div className="marked-section">
                                    <h3>Already Marked ({todayData.marked_count})</h3>
                                    <div className="attendance-table">
                                        <table>
                                            <thead>
                                                <tr>
                                                    <th>Worker Name</th>
                                                    <th>Position</th>
                                                    <th>Status</th>
                                                    <th>Actions</th>
                                                </tr>
                                            </thead>
                                            <tbody>
                                                {todayData.marked_attendances?.map(attendance => (
                                                    <tr key={attendance.id}>
                                                        <td>{attendance.worker?.name}</td>
                                                        <td>{attendance.worker?.position}</td>
                                                        <td>
                                                            <span className={getStatusBadgeClass(attendance.status)}>
                                                                {attendance.status.replace('_', ' ')}
                                                            </span>
                                                        </td>
                                                        <td>
                                                            <button
                                                                className="btn btn-sm btn-danger"
                                                                onClick={() => handleDeleteAttendance(attendance.id)}
                                                            >
                                                                Delete
                                                            </button>
                                                        </td>
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            )}
                        </>
                    ) : (
                        <div className="error-container">
                            <div className="error-icon">⚠️</div>
                            <p>Failed to load attendance data</p>
                            <button className="btn btn-primary" onClick={fetchTodayAttendance}>
                                Retry
                            </button>
                        </div>
                    )}
                </div>
            )}

            {/* History Tab */}
            {activeTab === 'history' && (
                <div className="history-tab">
                    <div className="filters">
                        <div className="filters-left">
                            <input
                                type="text"
                                value={workerSearch}
                                onChange={(e) => setWorkerSearch(e.target.value)}
                                placeholder="🔍 Search worker..."
                                className="search-input"
                            />
                        </div>
                        <div className="filters-right">
                            <input
                                type="date"
                                value={filters.date}
                                onChange={(e) => setFilters({ ...filters, date: e.target.value })}
                                placeholder="Filter by date"
                            />
                            <select
                                value={filters.status}
                                onChange={(e) => setFilters({ ...filters, status: e.target.value })}
                            >
                                <option value="">All Status</option>
                                <option value="present">Present</option>
                                <option value="absent">Absent</option>
                                <option value="half_day">Half Day</option>
                                <option value="leave">Leave</option>
                            </select>
                            <button 
                                className="btn btn-secondary"
                                onClick={() => {
                                    setFilters({ date: '', worker_id: '', status: '' });
                                    setWorkerSearch('');
                                }}
                            >
                                Clear All
                            </button>
                        </div>
                    </div>

                    <div className="attendance-table">
                        <table>
                            <thead>
                                <tr>
                                    <th>Date</th>
                                    <th>Worker Name</th>
                                    <th>Position</th>
                                    <th>Status</th>
                                    <th>Marked By</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {loading ? (
                                    <tr>
                                        <td colSpan="8" style={{ textAlign: 'center' }}>Loading...</td>
                                    </tr>
                                ) : filterWorkersBySearch(attendanceHistory).length === 0 ? (
                                    <tr>
                                        <td colSpan="6" style={{ textAlign: 'center' }}>
                                            {workerSearch ? `No records found for "${workerSearch}"` : 'No attendance records found'}
                                        </td>
                                    </tr>
                                ) : (
                                    filterWorkersBySearch(attendanceHistory).map(attendance => (
                                        <tr key={attendance.id}>
                                            <td>{formatDate(attendance.date)}</td>
                                            <td>{attendance.worker?.name}</td>
                                            <td>{attendance.worker?.position}</td>
                                            <td>
                                                <span className={getStatusBadgeClass(attendance.status)}>
                                                    {attendance.status.replace('_', ' ')}
                                                </span>
                                            </td>
                                            <td>{attendance.marked_by?.name || 'N/A'}</td>
                                            <td>
                                                <button
                                                    className="btn btn-sm btn-danger"
                                                    onClick={() => handleDeleteAttendance(attendance.id)}
                                                >
                                                    Delete
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* Summary Tab */}
            {activeTab === 'summary' && (
                <div className="summary-tab">
                    <div className="date-range">
                        <label>
                            Start Date
                            <input
                                type="date"
                                value={startDate}
                                onChange={(e) => setStartDate(e.target.value)}
                            />
                        </label>
                        <label>
                            End Date
                            <input
                                type="date"
                                value={endDate}
                                onChange={(e) => setEndDate(e.target.value)}
                            />
                        </label>
                    </div>

                    {summary && (
                        <div className="summary-cards">
                            <div className="summary-card total">
                                <div className="summary-icon">📊</div>
                                <h3>Total Records</h3>
                                <div className="summary-value">{summary.total_records}</div>
                            </div>
                            <div className="summary-card present">
                                <div className="summary-icon">✅</div>
                                <h3>Present</h3>
                                <div className="summary-value">{summary.present}</div>
                                <div className="summary-percent">
                                    {summary.total_records > 0 ? Math.round((summary.present / summary.total_records) * 100) : 0}%
                                </div>
                            </div>
                            <div className="summary-card absent">
                                <div className="summary-icon">❌</div>
                                <h3>Absent</h3>
                                <div className="summary-value">{summary.absent}</div>
                                <div className="summary-percent">
                                    {summary.total_records > 0 ? Math.round((summary.absent / summary.total_records) * 100) : 0}%
                                </div>
                            </div>
                            <div className="summary-card half-day">
                                <div className="summary-icon">⏰</div>
                                <h3>Half Day</h3>
                                <div className="summary-value">{summary.half_day}</div>
                                <div className="summary-percent">
                                    {summary.total_records > 0 ? Math.round((summary.half_day / summary.total_records) * 100) : 0}%
                                </div>
                            </div>
                            <div className="summary-card leave">
                                <div className="summary-icon">🏖️</div>
                                <h3>Leave</h3>
                                <div className="summary-value">{summary.leave}</div>
                                <div className="summary-percent">
                                    {summary.total_records > 0 ? Math.round((summary.leave / summary.total_records) * 100) : 0}%
                                </div>
                            </div>
                        </div>
                    )}

                    {!summary && (
                        <div className="loading-summary">
                            <p>Loading summary...</p>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

export default AttendanceManagement;
